class Solution:
    def lenLongestFibSubseq(self, arr):
        """
        :type arr: List[int]
        :rtype: int
        """
        n = len(arr)
        val_to_idx = {arr[i]: i for i in range(n)}

        # dp[i][j] = length of Fibonacci sequence ending at arr[j] with previous element arr[i]
        dp = [[2] * n for _ in range(n)]
        max_len = 0

        for j in range(2, n):
            for i in range(1, j):
                # Find k such that arr[k] + arr[i] = arr[j]
                prev = arr[j] - arr[i]

                if prev in val_to_idx:
                    k = val_to_idx[prev]
                    if k < i:
                        dp[i][j] = dp[k][i] + 1
                        max_len = max(max_len, dp[i][j])

        return max_len if max_len >= 3 else 0
